214	error_t uc_batch_dl_finite_difference_impl_t::verify(const std::vector<ecc_point_t>& Q, mem_t session_id,
215	                                                     uint64_t aux) const {
216	  error_t rv = UNINITIALIZED_ERROR;
217	  int n = int(Q.size());
218	  if (n <= 0) return coinbase::error(E_CRYPTO, "uc_batch_dl_t::verify: Q.size() <= 0");
219	  crypto::vartime_scope_t vartime_scope;
220	  const int b_minus_log2n = params.b - int_log2(n);
221	  if (rv = params.check_with_effective_b(b_minus_log2n)) return rv;
222	  int rho = params.rho;
223	  if (int(R.size()) != rho)
224	    return coinbase::error(E_CRYPTO, "uc_batch_dl_finite_difference_impl_t::verify: R.size() != rho");
225	  if (int(e.size()) != rho)
226	    return coinbase::error(E_CRYPTO, "uc_batch_dl_finite_difference_impl_t::verify: e.size() != rho");
227	  if (int(z.size()) != rho)
228	    return coinbase::error(E_CRYPTO, "uc_batch_dl_finite_difference_impl_t::verify: z.size() != rho");
229	
230	  ecurve_t curve = Q[0].get_curve();
231	  const mod_t& q = curve.order();
232	
233	  for (int j = 0; j < n; j++) {
234	    if (rv = curve.check(Q[j]))
235	      return coinbase::error(rv, "uc_batch_dl_finite_difference_impl_t::verify: Q[j] is not on the curve");
236	  }
237	
238	  const auto& G = curve.generator();
239	  uint32_t b_mask = params.b_mask();
240	  for (int i = 0; i < rho; i++) {
241	    if (rv = curve.check(R[i]))
242	      return coinbase::error(rv, "uc_batch_dl_finite_difference_impl_t::verify: R[i] is not on the curve");
243	  }
244	  buf_t common_hash = crypto::ro::hash_string(G, Q, R, session_id, aux).bitlen(2 * SEC_P_COM);
245	
246	  std::vector<ecc_point_t> PQ(n + 1);
247	  PQ[0] = curve.infinity();
248	  for (int i = 0; i < n; i++) PQ[i + 1] = Q[i];
249	
250	  for (int i = 0; i < rho; i++) {
251	    if (rv = crypto::check_right_open_range(0, z[i], q)) return rv;
252	
253	    bn_t ei = e[i];
254	    if (ei < 0) ei += q;
255	
256	    ecc_point_t R_test = z[i] * G - crypto::horner_poly(PQ, ei);
257	    if (R[i] != R_test)
258	      return coinbase::error(E_CRYPTO, "uc_batch_dl_finite_difference_impl_t::verify: R[i] does not match");
259	
260	    uint32_t h = hash32bit_for_zk_fischlin(common_hash, i, e[i], z[i]) & b_mask;
261	    if (h != 0)
262	      return coinbase::error(E_CRYPTO, "uc_batch_dl_finite_difference_impl_t::verify: zk_fischlin hash not equal zero");
263	  }
264	
265	  return SUCCESS;
266	}
