6	void fischlin_prove(const fischlin_params_t& params, std::function<void()> initialize,
7	                    std::function<void(int index)> response_begin, std::function<uint32_t(int index, int e_tag)> hash,
8	                    std::function<void(int index, int e_tag)> save, std::function<void(int e_tag)> response_next) {
9	  int e_max = params.e_max();
10	  uint32_t b_mask = params.b_mask();
11	  int rho = params.rho;
12	
13	  while (true) {
14	    bool rho_e_tags_found = true;
15	    // This function maps to the loop that runs zkClaim in the spec and the common hash that is done after that
16	    initialize();
17	
18	    for (int i = 0; i < rho; i++) {
19	      bool e_tag_found = false;
20	
21	      // This function performs any special initializations. Specifically, this runs the special case of zkResponse for
22	      // the first iteration. Subsequent zkResponses are handled by the "next" function. For example, for an optimized
23	      // version of Fischlin for ZK-DL, instead of computing `z_tag = sigma + e . w` inside a dedicated zkResponse
24	      // function, this function sets the initial z_tag = sigma and in the "next" function, incrementally update it as
25	      // `z_tag += w` (since e is incremented by one in each iteration).
26	      response_begin(i);
27	      for (int e_tag = 0; e_tag < e_max; e_tag++) {
28	        // This function internally handles the "common hash" value that was generated by the "restart" function
29	        uint32_t h = hash(i, e_tag) & b_mask;
30	        if (h != 0) {
31	          // This function handles zkRespones and prepares for the next iteration.
32	          if (e_tag + 1 < e_max) response_next(e_tag + 1);
33	          continue;
34	        }
35	
36	        // This function stores the e_i and z_i in the proper location of the array
37	        save(i, e_tag);
38	        e_tag_found = true;
39	        break;
40	      }
41	
42	      if (!e_tag_found) {
43	        rho_e_tags_found = false;
44	        break;
45	      }
46	    }
47	    if (rho_e_tags_found) break;
48	  }
49	}
