7	void valid_paillier_t::prove(const crypto::paillier_t& paillier, mem_t session_id, uint64_t aux) {
8	  cb_assert(paillier.has_private_key());
9	  const mod_t& N = paillier.get_N();
10	  const bn_t& phi_N = paillier.get_phi_N();
11	
12	  bn_t N_inv = mod_t::N_inv_mod_phiN_2048(N, phi_N);
13	
14	  static_assert(SEC_P_COM == 128, "security parameter changed, please update the code");
15	  buf128_t k = crypto::ro::hash_string(N, session_id, aux).bitlen128();
16	  crypto::drbg_aes_ctr_t drbg(k);
17	
18	  for (int i = 0; i < param::t; i++) {
19	    bn_t rho = drbg.gen_bn(N);
20	    sigma[i] = rho.pow_mod(N_inv, N);
21	  }
22	}
