24	error_t valid_paillier_t::verify(const crypto::paillier_t& paillier, mem_t session_id, uint64_t aux) {
25	  crypto::vartime_scope_t vartime_scope;
26	  error_t rv = UNINITIALIZED_ERROR;
27	  const mod_t& N = paillier.get_N();
28	
29	  buf128_t k = crypto::ro::hash_string(N, session_id, aux).bitlen128();
30	  crypto::drbg_aes_ctr_t drbg(k);
31	
32	  if (N <= 0) return coinbase::error(E_CRYPTO);
33	  if (paillier_no_small_factors == zk_flag::unverified) {
34	    if (rv = check_integer_with_small_primes(N, param::alpha)) return rv;
35	    paillier_no_small_factors = zk_flag::verified;
36	  }
37	
38	  bn_t rho_prod = 1;
39	  for (int i = 0; i < param::t; i++) {
40	    bn_t rho = drbg.gen_bn(N);
41	    MODULO(N) rho_prod *= rho;
42	    if (sigma[i] <= 0) return coinbase::error(E_CRYPTO);
43	    if (sigma[i].pow_mod(N, N) != rho) return coinbase::error(E_CRYPTO);
44	  }
45	  if (!mod_t::coprime(rho_prod, N)) return coinbase::error(E_CRYPTO);
46	  paillier_valid_key = zk_flag::verified;
47	  return SUCCESS;
48	}
