55	void valid_paillier_interactive_t::valid_paillier_interactive_t::prove(const crypto::paillier_t& paillier,
56	                                                                       const challenge_msg_t& challenge_msg,
57	                                                                       const crypto::mpc_pid_t& prover_pid,
58	                                                                       prover_msg_t& prover_msg) const {
59	  cb_assert(paillier.has_private_key());
60	  const mod_t& N = paillier.get_N();
61	  const bn_t& phi_N = paillier.get_phi_N();
62	
63	  bn_t N_inv = mod_t::N_inv_mod_phiN_2048(N, phi_N);
64	
65	  buf128_t k = crypto::ro::hash_string(challenge_msg.kV, N, prover_pid).bitlen128();
66	  crypto::drbg_aes_ctr_t drbg(k);
67	
68	  for (int i = 0; i < param::t; i++) {
69	    // Our assumption is that this function is only going to be used with moduli with large primes.
70	    // Therefore as stated in the spec we don’t need to do the coprime check.
71	    bn_t rho = drbg.gen_bn(N);
72	    prover_msg.sigma[i] = rho.pow_mod(N_inv, N);
73	  }
74	}
