76	error_t valid_paillier_interactive_t::verify(const crypto::paillier_t& paillier, const crypto::mpc_pid_t& prover_pid,
77	                                             const prover_msg_t& prover_msg) {
78	  crypto::vartime_scope_t vartime_scope;
79	
80	  error_t rv = UNINITIALIZED_ERROR;
81	  const mod_t& N = paillier.get_N();
82	  buf128_t k = crypto::ro::hash_string(kV, N, prover_pid).bitlen128();
83	  crypto::drbg_aes_ctr_t drbg(k);
84	
85	  if (N <= 0) return coinbase::error(E_CRYPTO);
86	  if (paillier_no_small_factors == zk_flag::unverified) {
87	    if (rv = check_integer_with_small_primes(N, param::alpha)) return rv;
88	    paillier_no_small_factors = zk_flag::verified;
89	  }
90	
91	  bn_t rho_prod = 1;
92	  for (int i = 0; i < param::t; i++) {
93	    bn_t rho = drbg.gen_bn(N);
94	    MODULO(N) rho_prod *= rho;
95	
96	    if (prover_msg.sigma[i] <= 0) return coinbase::error(E_CRYPTO);
97	    if (prover_msg.sigma[i].pow_mod(N, N) != rho) return coinbase::error(E_CRYPTO);
98	  }
99	
100	  if (!mod_t::coprime(rho_prod, N)) return coinbase::error(E_CRYPTO);
101	  paillier_valid_key = zk_flag::verified;
102	  return SUCCESS;
103	}
