107	// only 13 bits used from each 16 bits block (uint16_t).
108	// 16 bits are used for simpler splitting using uint16_t
109	
110	void paillier_zero_t::prove(const crypto::paillier_t& paillier, const bn_t& c, const bn_t& r, mem_t session_id,
111	                            uint64_t aux) {
112	  // In our use cases, all our provers have private keys. If not, we would need to verify that gcd(rho_i,N) = 1
113	  cb_assert(paillier.has_private_key());
114	  const mod_t& N = paillier.get_N();
115	  const mod_t& NN = paillier.get_NN();
116	  // This is the statement that we want to prove. Adding it here as a sanity check.
117	  // If this causes efficiency issues, it can be removed and the caller must ensure that the ciphertext is valid.
118	  cb_assert(r.pow_mod(N, NN) == c);
119	
120	  bn_t rho[param::t];
121	  bn_t a[param::t];
122	
123	  for (int i = 0; i < param::t; i++) {
124	    rho[i] = bn_t::rand(N);
125	    a[i] = rho[i].pow_mod(N, NN);
126	  }
127	
128	  e = crypto::ro::hash_string(N, c, a, session_id, aux)
129	          .bitlen(param::padded_log_alpha * param::t);  // use only 13 bits for each ei
130	
131	  for (int i = 0; i < param::t; i++) {
132	    bn_t ei = param::get_log_alpha_bits(e, i);
133	    MODULO(N) z[i] = rho[i] * r.pow(ei);
134	  }
135	}
