137	error_t paillier_zero_t::verify(const crypto::paillier_t& paillier, const bn_t& c, mem_t session_id, uint64_t aux) {
138	  crypto::vartime_scope_t vartime_scope;
139	
140	  error_t rv = UNINITIALIZED_ERROR;
141	  if (paillier_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
142	
143	  const mod_t& N = paillier.get_N();
144	  const mod_t& NN = paillier.get_NN();
145	
146	  if (paillier_no_small_factors == zk_flag::unverified) {
147	    if (rv = check_integer_with_small_primes(N, valid_paillier_t::param::alpha)) return rv;
148	    paillier_no_small_factors = zk_flag::verified;
149	  }
150	
151	  if (paillier_valid_ciphertext == zk_flag::unverified) {
152	    if (rv = paillier.verify_cipher(c)) return rv;
153	    paillier_valid_ciphertext = zk_flag::verified;
154	  }
155	  if (e.size() != bits_to_bytes(param::padded_log_alpha * param::t))
156	    return coinbase::error(E_CRYPTO);  // use only 13 bits for each ei
157	
158	  bn_t d = NN.inv(c);
159	  bn_t a[param::t];
160	
161	  bn_t z_prod = 1;
162	  for (int i = 0; i < param::t; i++) {
163	    MODULO(N) z_prod *= z[i];
164	    bn_t ei = param::get_log_alpha_bits(e, i);
165	    MODULO(NN) a[i] = z[i].pow(N) * d.pow(ei);
166	  }
167	  if (z_prod == 0 || !mod_t::coprime(z_prod, N)) return coinbase::error(E_CRYPTO);
168	
169	  buf_t e_tag = crypto::ro::hash_string(N, c, a, session_id, aux)
170	                    .bitlen(param::padded_log_alpha * param::t);  // use only 13 bits for each ei
171	  if (e != e_tag) return coinbase::error(E_CRYPTO);
172	  return SUCCESS;
173	}
