175	void two_paillier_equal_t::prove(const mod_t& q, const crypto::paillier_t& P0, const bn_t& c0,
176	                                 const crypto::paillier_t& P1, const bn_t& c1, const bn_t& x, const bn_t& r0,
177	                                 const bn_t& r1, mem_t session_id, uint64_t aux) {
178	  cb_assert(P0.has_private_key());
179	  cb_assert(P1.has_private_key());
180	
181	  const mod_t& N0 = P0.get_N();
182	  const mod_t& N1 = P1.get_N();
183	
184	  int test_len = q.get_bits_count() + param::log_alpha + SEC_P_STAT + 1;
185	  cb_assert(N0.get_bits_count() >= std::max(2048, test_len));
186	  cb_assert(N1.get_bits_count() >= std::max(2048, test_len));
187	
188	  bn_t q_with_slack = q << (param::log_alpha + SEC_P_STAT);
189	
190	  bn_t tau[param::t];
191	  bn_t R0_tilde[param::t];
192	  bn_t R1_tilde[param::t];
193	
194	  crypto::paillier_t::elem_t c0_tilde[param::t];
195	  crypto::paillier_t::elem_t c1_tilde[param::t];
196	
197	  for (int i = 0; i < param::t; i++) {
198	    tau[i] = bn_t::rand(q_with_slack);
199	
200	    R0_tilde[i] = bn_t::rand(N0);
201	    c0_tilde[i] = P0.enc(tau[i], R0_tilde[i]);
202	
203	    R1_tilde[i] = bn_t::rand(N1);
204	    c1_tilde[i] = P1.enc(tau[i], R1_tilde[i]);
205	  }
206	
207	  e = crypto::ro::hash_string(N0, c0, N1, c1, c0_tilde, c1_tilde, session_id, aux)
208	          .bitlen(param::t * param::padded_log_alpha);  // only 13 bits are used for each ei
209	
210	  for (int i = 0; i < param::t; i++) {
211	    bn_t ei = param::get_log_alpha_bits(e, i);
212	    // Side-channel note:
213	    // - `ei` is public and small (only `param::padded_log_alpha` bits, currently 13) derived from a RO hash.
214	    // - `x` is sampled modulo a fixed-size `q` (so its limb-length is effectively fixed for valid inputs).
215	    // - The main leak vector for bignum multiplication is operand length (`top`), which is not meaningfully
216	    //   data-dependent here in our threat model. If this ever becomes a high-resolution local side-channel
217	    //   concern, consider enforcing fixed-top arithmetic for `x` before this multiply.
218	    d[i] = ei * x + tau[i];
219	    MODULO(N0) r0_hat[i] = r0.pow(ei) * R0_tilde[i];
220	    MODULO(N1) r1_hat[i] = r1.pow(ei) * R1_tilde[i];
221	  }
222	}
