224	error_t two_paillier_equal_t::verify(const mod_t& q, const crypto::paillier_t& P0, const bn_t& c0,  // old
225	                                     const crypto::paillier_t& P1, const bn_t& c1,                  // new
226	                                     mem_t session_id, uint64_t aux) {
227	  crypto::vartime_scope_t vartime_scope;
228	  error_t rv = UNINITIALIZED_ERROR;
229	
230	  const mod_t& N0 = P0.get_N();
231	  const mod_t& N1 = P1.get_N();
232	
233	  if (bn_t(N0) <= 0) return rv = coinbase::error(E_CRYPTO);
234	  if (bn_t(N1) <= 0) return rv = coinbase::error(E_CRYPTO);
235	
236	  int test_len = q.get_bits_count() + param::log_alpha + SEC_P_STAT + 1;
237	  if (N0.get_bits_count() < std::max(crypto::paillier_t::bit_size, test_len)) return rv = coinbase::error(E_CRYPTO);
238	  if (N1.get_bits_count() < std::max(crypto::paillier_t::bit_size, test_len)) return rv = coinbase::error(E_CRYPTO);
239	
240	  if (p0_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
241	  if (p1_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
242	
243	  if (c0_plaintext_range == zk_flag::unverified) return coinbase::error(E_CRYPTO);
244	
245	  if (p0_valid_ciphertext == zk_flag::unverified) {
246	    if (rv = P0.verify_cipher(c0)) return rv;
247	    p0_valid_ciphertext = zk_flag::verified;
248	  }
249	  if (p1_valid_ciphertext == zk_flag::unverified) {
250	    if (rv = P1.verify_cipher(c1)) return rv;
251	    p1_valid_ciphertext = zk_flag::verified;
252	  }
253	  if (p0_no_small_factors == zk_flag::unverified) {
254	    if (rv = check_integer_with_small_primes(N0, valid_paillier_t::param::alpha)) return rv;
255	    p0_no_small_factors = zk_flag::verified;
256	  }
257	  if (p1_no_small_factors == zk_flag::unverified) {
258	    if (rv = check_integer_with_small_primes(N1, valid_paillier_t::param::alpha)) return rv;
259	    p1_no_small_factors = zk_flag::verified;
260	  }
261	
262	  if (bn_t(N0) <= 0) return coinbase::error(E_CRYPTO);
263	  if (bn_t(N1) <= 0) return coinbase::error(E_CRYPTO);
264	
265	  if (e.size() != coinbase::bits_to_bytes(param::t * param::padded_log_alpha))
266	    return coinbase::error(E_CRYPTO);  // only 13 bits are used for each ei
267	
268	  const mod_t& NN0 = P0.get_NN();
269	  const mod_t& NN1 = P1.get_NN();
270	  bn_t q_with_slack = q << (param::log_alpha + SEC_P_STAT);
271	
272	  crypto::paillier_t::elem_t c0_tilde[param::t];
273	  crypto::paillier_t::elem_t c1_tilde[param::t];
274	  bn_t c0_inv = NN0.inv(c0);
275	  bn_t c1_inv = NN1.inv(c1);
276	
277	  bn_t r0_hat_prod = 1;
278	  bn_t r1_hat_prod = 1;
279	  for (int i = 0; i < param::t; i++) {
280	    if (rv = coinbase::crypto::check_right_open_range(0, d[i], q_with_slack)) return rv;
281	
282	    bn_t ei = param::get_log_alpha_bits(e, i);
283	
284	    if (r0_hat[i] <= 0) return coinbase::error(E_CRYPTO);
285	    if (r1_hat[i] <= 0) return coinbase::error(E_CRYPTO);
286	
287	    MODULO(N0) r0_hat_prod *= r0_hat[i];
288	    MODULO(N1) r1_hat_prod *= r1_hat[i];
289	
290	    crypto::paillier_t::rerand_scope_t paillier_rerand(crypto::paillier_t::rerand_e::off);
291	    c0_tilde[i] = P0.enc(d[i], r0_hat[i]) + P0.elem(c0_inv.pow_mod(ei, NN0));
292	    c1_tilde[i] = P1.enc(d[i], r1_hat[i]) + P1.elem(c1_inv.pow_mod(ei, NN1));
293	  }
294	  if (!mod_t::coprime(r0_hat_prod, N0)) return coinbase::error(E_CRYPTO);
295	  if (!mod_t::coprime(r1_hat_prod, N1)) return coinbase::error(E_CRYPTO);
296	
297	  buf_t e_tag = crypto::ro::hash_string(N0, c0, N1, c1, c0_tilde, c1_tilde, session_id, aux)
298	                    .bitlen(param::t * param::padded_log_alpha);  // only 13 bits are used for each ei
299	  if (e_tag != e) return coinbase::error(E_CRYPTO);
300	  c1_plaintext_range = zk_flag::verified;
301	  return SUCCESS;
302	}
