340	error_t two_paillier_equal_interactive_t::prover_msg2(const crypto::paillier_t& P0, const crypto::paillier_t& P1,
341	                                                      const bn_t& x, const bn_t& r0, const bn_t& r1,
342	                                                      const verifier_challenge_msg_t& challenge_msg,
343	                                                      prover_msg2_t& msg2) const {
344	  if (coinbase::bits_to_bytes(param::t * param::padded_log_alpha) != challenge_msg.e.size())
345	    return coinbase::error(E_FORMAT);  // only 13 bits are used for each ei
346	  const mod_t& N0 = P0.get_N();
347	  const mod_t& N1 = P1.get_N();
348	
349	  for (int i = 0; i < param::t; i++) {
350	    bn_t ei = param::get_log_alpha_bits(challenge_msg.e, i);
351	    // Side-channel note: same rationale as in `two_paillier_equal_t::prove` for `d[i] = ei * x + tau[i]`.
352	    // Here `ei` is a public short challenge (13 bits), and `x` is modulo fixed-size `q`.
353	    msg2.d[i] = ei * x + tau[i];
354	    MODULO(N0) msg2.r0_hat[i] = r0.pow(ei) * R0_tilde[i];
355	    MODULO(N1) msg2.r1_hat[i] = r1.pow(ei) * R1_tilde[i];
356	    msg2.c0_tilde[i] = c0_tilde[i];
357	    msg2.c1_tilde[i] = c1_tilde[i];
358	  }
359	  msg2.com_rand = com_rand;
360	  return SUCCESS;
361	}
