363	error_t two_paillier_equal_interactive_t::verify(const mod_t& q, const crypto::paillier_t& P0,
364	                                                 const bn_t& c0,                                // old
365	                                                 const crypto::paillier_t& P1, const bn_t& c1,  // new
366	                                                 const prover_msg1_t& msg1, const prover_msg2_t& msg2) {
367	  crypto::vartime_scope_t vartime_scope;
368	  error_t rv = UNINITIALIZED_ERROR;
369	
370	  const mod_t& N0 = P0.get_N();
371	  const mod_t& N1 = P1.get_N();
372	
373	  const mod_t& NN0 = P0.get_NN();
374	  const mod_t& NN1 = P1.get_NN();
375	
376	  if (bn_t(N0) <= 0) return rv = coinbase::error(E_CRYPTO);
377	  if (bn_t(N1) <= 0) return rv = coinbase::error(E_CRYPTO);
378	  int test_len = q.get_bits_count() + param::log_alpha + SEC_P_STAT + 1;
379	  if (N0.get_bits_count() < std::max(crypto::paillier_t::bit_size, test_len)) return rv = coinbase::error(E_CRYPTO);
380	  if (N1.get_bits_count() < std::max(crypto::paillier_t::bit_size, test_len)) return rv = coinbase::error(E_CRYPTO);
381	
382	  crypto::commitment_t com(prover_pid);
383	  if (rv = com.set(msg2.com_rand, msg1.com_msg).open(msg2.c0_tilde, msg2.c1_tilde)) return rv;
384	
385	  if (p0_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
386	  if (p1_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
387	
388	  if (c0_plaintext_range == zk_flag::unverified) return coinbase::error(E_CRYPTO);
389	
390	  if (p0_valid_ciphertext == zk_flag::unverified) {
391	    if (rv = P0.verify_cipher(c0)) return rv;
392	    p0_valid_ciphertext = zk_flag::verified;
393	  }
394	
395	  if (p1_valid_ciphertext == zk_flag::unverified) {
396	    if (rv = P1.verify_cipher(c1)) return rv;
397	    p1_valid_ciphertext = zk_flag::verified;
398	  }
399	
400	  if (p0_no_small_factors == zk_flag::unverified) {
401	    if (rv = check_integer_with_small_primes(N0, valid_paillier_t::param::alpha)) return rv;
402	    p0_no_small_factors = zk_flag::verified;
403	  }
404	
405	  if (p1_no_small_factors == zk_flag::unverified) {
406	    if (rv = check_integer_with_small_primes(N1, valid_paillier_t::param::alpha)) return rv;
407	    p1_no_small_factors = zk_flag::verified;
408	  }
409	
410	  bn_t q_with_slack = q << (param::log_alpha + SEC_P_STAT);
411	
412	  if (coinbase::bits_to_bytes(param::t * param::padded_log_alpha) != e.size())
413	    return coinbase::error(E_FORMAT);  // only 13 bits are used for each ei
414	
415	  bn_t H0_test = c0, H1_test = c1;
416	  for (int i = 0; i < param::t; i++) {
417	    if (rv = coinbase::crypto::check_right_open_range(0, msg2.d[i], q_with_slack)) return rv;
418	
419	    if (msg2.r0_hat[i] <= 0) return coinbase::error(E_CRYPTO);
420	    if (msg2.r1_hat[i] <= 0) return coinbase::error(E_CRYPTO);
421	
422	    MODULO(N0) H0_test *= msg2.r0_hat[i] * msg2.c0_tilde[i];
423	    MODULO(N1) H1_test *= msg2.r1_hat[i] * msg2.c1_tilde[i];
424	
425	    bn_t ei = param::get_log_alpha_bits(e, i);
426	    bn_t t0, t1;
427	    MODULO(NN0) t0 = c0.pow(ei) * msg2.c0_tilde[i];
428	    MODULO(NN1) t1 = c1.pow(ei) * msg2.c1_tilde[i];
429	
430	    if (t0 != P0.encrypt(msg2.d[i], msg2.r0_hat[i])) return coinbase::error(E_CRYPTO);
431	    if (t1 != P1.encrypt(msg2.d[i], msg2.r1_hat[i])) return coinbase::error(E_CRYPTO);
432	  }
433	
434	  if (H0_test == 0) return coinbase::error(E_CRYPTO);
435	  if (H1_test == 0) return coinbase::error(E_CRYPTO);
436	  if (!mod_t::coprime(H0_test, N0)) return coinbase::error(E_CRYPTO);
437	  if (!mod_t::coprime(H1_test, N1)) return coinbase::error(E_CRYPTO);
438	
439	  c1_plaintext_range = zk_flag::verified;
440	  return SUCCESS;
441	}
