443	void pdl_t::prove(const bn_t& c_key, const crypto::paillier_t& paillier, const ecc_point_t& Q1, const bn_t& x1,
444	                  const bn_t& r_key, mem_t sid, uint64_t aux) {
445	  // In our use cases, all our provers have private keys. If not, we would need to verify that gcd(r_rand,N) = 1
446	  cb_assert(paillier.has_private_key());
447	
448	  ecurve_t curve = Q1.get_curve();
449	  const mod_t& q = curve.order();
450	  const auto& G = curve.generator();
451	  const mod_t& N = paillier.get_N();
452	
453	  bn_t qq = q * q;
454	  cb_assert(N.get_bits_count() >= 2048 && N >= ((qq << (SEC_P_STAT + 1)) + (qq << 1)));
455	
456	  bn_t r_rand = bn_t::rand(N);
457	
458	  // We sample r from Z_{q^2*2^kappa} in the indirect way to avoid non-constant time mod when calculating r * G
459	  bn_t r_mod_q = bn_t::rand(q);
460	  bn_t r = bn_t::rand(q << SEC_P_STAT) * q + r_mod_q;
461	  c_r = paillier.encrypt(r, r_rand);
462	  R = r_mod_q * G;
463	
464	  bn_t e = crypto::ro::hash_number(c_key, N, Q1, c_r, R, sid, aux).mod(q);
465	  // Side-channel note:
466	  // `e` is a public RO-derived challenge. The arithmetic `e * x1` uses bignum ops; for valid inputs `x1` is modulo
467	  // fixed-size `q`, so operand limb-length is effectively fixed (the dominant timing driver in typical BN code).
468	  z = r + e * x1;
469	  MODULO(N) r_z = r_rand * r_key.pow_mod(e, N);
470	
471	  if (paillier_range_exp_slack_proof != zk_flag::skip) {
472	    zk_paillier_range_exp_slack.prove(paillier, q, c_key, x1, r_key, sid, aux);
473	  }
474	}
