476	error_t pdl_t::verify(const bn_t& c_key, const crypto::paillier_t& paillier, const ecc_point_t& Q1, mem_t sid,
477	                      uint64_t aux) {
478	  crypto::paillier_t::rerand_scope_t paillier_rerand(crypto::paillier_t::rerand_e::off);
479	  crypto::vartime_scope_t vartime_scope;
480	  error_t rv = UNINITIALIZED_ERROR;
481	
482	  const mod_t& N = paillier.get_N();
483	  ecurve_t curve = Q1.get_curve();
484	  if (!curve) return coinbase::error(E_CRYPTO, "pdl_t::verify: Q1 curve is null");
485	  const mod_t& q = curve.order();
486	  const auto& G = curve.generator();
487	
488	  if (rv = curve.check(Q1)) return coinbase::error(rv, "pdl_t::verify: Q1 is not a valid curve point");
489	  {
490	    crypto::allow_ecc_infinity_t allow_infinity;
491	    if (rv = curve.check(R)) return coinbase::error(rv, "pdl_t::verify: R is not a valid curve point");
492	  }
493	
494	  bn_t e = crypto::ro::hash_number(c_key, N, Q1, c_r, R, sid, aux).mod(q);
495	
496	  if (paillier_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
497	  if (paillier_no_small_factors == zk_flag::unverified) {
498	    if (rv = check_integer_with_small_primes(N, valid_paillier_t::param::alpha)) return rv;
499	    paillier_no_small_factors = zk_flag::verified;
500	  }
501	  if (paillier_valid_ciphertext == zk_flag::unverified) {
502	    if (rv = paillier.verify_cipher(c_key)) return rv;
503	    paillier_valid_ciphertext = zk_flag::verified;
504	  }
505	
506	  bn_t qq = q * q;
507	  if (N.get_bits_count() < 2048 || N <= ((qq << (SEC_P_STAT + 1)) + (qq << 1))) return coinbase::error(E_CRYPTO);
508	
509	  const mod_t& NN = paillier.get_NN();
510	  if (rv = coinbase::crypto::check_open_range(0, c_r, NN)) return rv;
511	
512	  bn_t gcd_test;
513	  MODULO(N) gcd_test = c_r * e * r_z;
514	  if (!mod_t::coprime(gcd_test, N)) return coinbase::error(E_CRYPTO);
515	
516	  if (z * G != R + e * Q1) return coinbase::error(E_CRYPTO);
517	
518	  if (z >= (qq + 1) << SEC_P_STAT) return coinbase::error(E_CRYPTO);
519	
520	  crypto::paillier_t::elem_t c_z = paillier.elem(c_r) + (paillier.elem(c_key) * e);
521	  if (paillier.encrypt(z, r_z) != c_z.to_bn()) return coinbase::error(E_CRYPTO);
522	
523	  if (paillier_range_exp_slack_proof != zk_flag::skip) {
524	    zk_paillier_range_exp_slack.paillier_valid_key = paillier_valid_key;
525	    zk_paillier_range_exp_slack.paillier_no_small_factors = paillier_no_small_factors;
526	    if (rv = zk_paillier_range_exp_slack.verify(paillier, q, c_key, sid, aux)) return rv;
527	  }
528	
529	  return SUCCESS;
530	}
