532	void paillier_range_exp_slack_t::prove(const crypto::paillier_t& paillier, const mod_t& q, const bn_t& c, const bn_t& x,
533	                                       const bn_t& r, mem_t session_id, uint64_t aux) {
534	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
535	  const mod_t& p_tag = params.p_tag;
536	  const mod_t& p = params.p;
537	  const bn_t& g = params.g;
538	  const bn_t& h = params.h;
539	
540	  bn_t rho = bn_t::rand(p_tag);
541	  MODULO(p) Com = g.pow(x) * h.pow(rho);
542	
543	  zk_paillier_pedersen_equal.prove(paillier, c, q, Com, x, r, rho, session_id, aux);
544	  zk_range_pedersen.prove(q, Com, x, rho, session_id, aux);
545	}
