57	void range_pedersen_t::prove(const bn_t& q, const bn_t& g, const bn_t& h, const bn_t& c, const bn_t& x, const bn_t& r,
58	                             mem_t session_id, uint64_t aux) {
59	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
60	  const mod_t& p_tag = params.p_tag;
61	  const mod_t& p = params.p;
62	  const bn_t& sqrt_h = params.sqrt_h;
63	  const bn_t& sqrt_g = params.sqrt_g;
64	
65	  bn_t q_with_slack = q << SEC_P_STAT;
66	
67	  cb_assert(check_right_open_range(0, x, q) == SUCCESS);
68	  cb_assert(p_tag > q_with_slack);
69	
70	  bn_t xi[t];
71	  bn_t ri[t];
72	  for (int i = 0; i < t; i++) {
73	    xi[i] = bn_t::rand(q_with_slack);
74	    ri[i] = bn_t::rand(p_tag);
75	    MODULO(p) c_tilde[i] = sqrt_g.pow(xi[i]) * sqrt_h.pow(ri[i]);
76	  }
77	
78	  e = crypto::ro::hash_string(p, q, g, h, c, c_tilde, session_id, aux).bitlen(t);
79	
80	  for (int i = 0; i < t; i++) {
81	    d[i] = xi[i];
82	    f[i] = ri[i];
83	    bool ei = e.get_bit(i);
84	    if (ei) {
85	      d[i] += x;
86	      MODULO(p_tag) f[i] += r;
87	    }
88	  }
89	}
