98	error_t range_pedersen_t::verify(const bn_t& q, const bn_t& g, const bn_t& h, const bn_t& c, mem_t session_id,
99	                                 uint64_t aux) const {
100	  error_t rv = UNINITIALIZED_ERROR;
101	  crypto::vartime_scope_t vartime_scope;
102	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
103	  const mod_t& p_tag = params.p_tag;
104	  const mod_t& p = params.p;
105	
106	  bn_t q_with_slack = q << SEC_P_STAT;
107	  if (p <= (q_with_slack << 1)) return coinbase::error(E_CRYPTO);
108	
109	  if (rv = params.check_safe_prime_subgroup(c)) return rv;
110	  // Subgroup checks for c_tildes are not done due to the optimizations described in the spec
111	
112	  // If in the future t != 128, then the the hash function should change to produce the output of length t
113	  cb_assert(t == 128);
114	  buf128_t e_tag = crypto::ro::hash_string(p, q, g, h, c, c_tilde, session_id, aux).bitlen128();
115	  if (e != e_tag) return coinbase::error(E_CRYPTO);
116	
117	  bn_t local_c_tilde[t];
118	  bn_t D = 0;
119	  bn_t F = 0;
120	  bn_t C = 1;
121	
122	  bn_t c_tilde2[t];
123	  for (int i = 0; i < t; i++) {
124	    if (rv = coinbase::crypto::check_right_open_range(0, d[i], q_with_slack)) return rv;
125	
126	    bool ei = e.get_bit(i);
127	
128	    if (rv = coinbase::crypto::check_open_range(0, c_tilde[i], p)) return rv;
129	
130	    // Related to the optimizations described in the spec
131	    MODULO(p) c_tilde2[i] = c_tilde[i] * c_tilde[i];
132	
133	    bn_t rho_i = bn_t::rand_bitlen(SEC_P_STAT);
134	
135	    MODULO(p_tag) {
136	      D += d[i] * rho_i;
137	      F += f[i] * rho_i;
138	    }
139	
140	    bn_t c_tilde_c_ei = c_tilde2[i];
141	    MODULO(p) {
142	      if (ei) c_tilde_c_ei *= c;
143	      C *= c_tilde_c_ei.pow(rho_i);
144	    }
145	  }
146	
147	  bn_t C_test;
148	  MODULO(p) C_test = g.pow(D) * h.pow(F);
149	  if (C != C_test) return coinbase::error(E_CRYPTO);
150	
151	  return SUCCESS;
152	}
