154	void range_pedersen_interactive_t::prover_msg1(const mod_t& q) {
155	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
156	  const mod_t& p_tag = params.p_tag;
157	  const mod_t& p = params.p;
158	  bn_t sqrt_h = params.sqrt_h;
159	  bn_t sqrt_g = params.sqrt_g;
160	
161	  // Type conversion used for assertions later on
162	  q_bn = q;
163	
164	  bn_t q_with_slack = q << SEC_P_STAT;
165	  cb_assert(p_tag > q_with_slack);
166	
167	  for (int i = 0; i < t; i++) {
168	    xi[i] = bn_t::rand(q_with_slack);
169	    ri[i] = bn_t::rand(p_tag);
170	    MODULO(p) c_tilde[i] = sqrt_g.pow(xi[i]) * sqrt_h.pow(ri[i]);
171	  }
172	  com.id(prover_pid).gen(c_tilde);
173	}
