188	  uint64_t e_temp = e;
189	  for (int i = 0; i < t; i++) {
190	    bool ei = (e_temp & 1) != 0;
191	    e_temp >>= 1;
192	
193	    d[i] = xi[i];
194	    f[i] = ri[i];
