203	error_t range_pedersen_interactive_t::verify(const bn_t& c, const mod_t& q) {
204	  error_t rv = UNINITIALIZED_ERROR;
205	  crypto::vartime_scope_t vartime_scope;
206	
207	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
208	  const mod_t& p_tag = params.p_tag;
209	  const mod_t& p = params.p;
210	  const bn_t& h = params.h;
211	  const bn_t& g = params.g;
212	
213	  if (rv = com.id(prover_pid).open(c_tilde)) return rv;
214	
215	  bn_t q_with_slack = q << SEC_P_STAT;
216	  if (p <= (q_with_slack << 1)) return coinbase::error(E_CRYPTO);
217	
218	  if (rv = params.check_safe_prime_subgroup(c)) return rv;
219	  // Same optimization as in the non-interactive version
220	
221	  bn_t D = 0, F = 0, C = 1;
222	  uint64_t e_temp = e;
223	  for (int i = 0; i < t; i++) {
224	    // Related to the optimizations described in the spec
225	    MODULO(p) c_tilde[i] *= c_tilde[i];
226	
227	    if (rv = coinbase::crypto::check_right_open_range(0, d[i], q_with_slack)) return rv;
228	    bn_t rho = bn_t::rand_bitlen(SEC_P_STAT);
229	
230	    MODULO(p_tag) {
231	      D += d[i] * rho;
232	      F += f[i] * rho;
233	    }
234	
235	    bool ei = (e_temp & 1) != 0;
236	    e_temp >>= 1;
237	
238	    bn_t Ci = c_tilde[i];
239	    if (ei) MODULO(p) Ci *= c;
240	    MODULO(p) C *= Ci.pow(rho);
241	  }
242	
243	  bn_t C_test;
244	  MODULO(p) C_test = g.pow(D) * h.pow(F);
245	  if (C_test != C) return coinbase::error(E_CRYPTO);
246	
247	  return SUCCESS;
248	}
