250	void paillier_pedersen_equal_t::prove(const crypto::paillier_t& paillier, const bn_t& c, const mod_t& q,
251	                                      const bn_t& Com, const bn_t& x, const bn_t& R, const bn_t& rho, mem_t session_id,
252	                                      uint64_t aux) {
253	  // In our use cases, all our provers have private keys. If not, we would need to verify that gcd(R_tilde[i],N) = 1
254	  cb_assert(paillier.has_private_key());
255	
256	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
257	  const mod_t& p_tag = params.p_tag;
258	  const mod_t& p = params.p;
259	  const bn_t& g = params.g;
260	  const bn_t& h = params.h;
261	
262	  const mod_t& N = paillier.get_N();
263	
264	  bn_t q_with_slack_N = q << (SEC_P_STAT + param::lambda + 2 * param::log_alpha + 1);
265	  cb_assert(N > q_with_slack_N);
266	
267	  bn_t q_with_slack_p = q << (SEC_P_STAT + param::lambda + param::log_alpha + 2);
268	  cb_assert(p > q_with_slack_p);
269	
270	  bn_t q_with_slack = q << (param::log_alpha + SEC_P_STAT);
271	  bn_t ri[param::t];
272	  bn_t R_tilde[param::t];
273	  crypto::paillier_t::elem_t c_tilde[param::t];
274	
275	  bn_t mu = bn_t::rand(p_tag);
276	  bn_t r = 0;
277	  for (int i = 0; i < param::t; i++) {
278	    ri[i] = bn_t::rand(q_with_slack);
279	    R_tilde[i] = bn_t::rand(N);
280	    c_tilde[i] = paillier.enc(ri[i], R_tilde[i]);
281	    r += ri[i] << (i * param::log_alpha);
282	  }
283	
284	  MODULO(p) Com_tilde = g.pow(r) * h.pow(mu);
285	
286	  buf_t e_buf =
287	      crypto::ro::hash_string(N, c, p, q, g, h, Com, c_tilde, Com_tilde, session_id, aux).bitlen(param::lambda);
288	  e = bn_t::from_bin_bitlen(e_buf, param::lambda);
289	
290	  bn_t e_temp = e;
291	
292	  for (int i = 0; i < param::t; i++) {
293	    bn_t ei;
294	    {
295	      crypto::vartime_scope_t vartime_scope;
296	      ei = mod_t::mod(e_temp, param::alpha);
297	    }
298	
299	    e_temp >>= param::log_alpha;
300	
301	    // Side-channel note:
302	    // - `ei` is a small public challenge chunk (mod alpha) extracted from a RO hash, and `x` is modulo `q`.
303	    // - The dominant timing signal in typical bignum multiplication is operand length; for valid inputs,
304	    //   `x` has a fixed bit-length (bounded by `q`), so this is not a meaningful leak in our threat model.
305	    // - If a strong local side-channel threat model is required, consider fixed-top arithmetic for `x`.
306	    di[i] = ei * x + ri[i];
307	
308	    MODULO(N) D[i] = R.pow(ei) * R_tilde[i];
309	  }
310	
311	  MODULO(p_tag) nu = e * rho + mu;
312	}
