314	error_t paillier_pedersen_equal_t::verify(const crypto::paillier_t& paillier, const bn_t& c, const mod_t& q,
315	                                          const bn_t& Com, mem_t session_id, uint64_t aux) {
316	  crypto::vartime_scope_t vartime_scope;
317	
318	  error_t rv = UNINITIALIZED_ERROR;
319	  if (paillier_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
320	
321	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
322	  const mod_t& p = params.p;
323	  const bn_t& g = params.g;
324	  const bn_t& h = params.h;
325	
326	  bn_t q_with_slack_p = q << (SEC_P_STAT + param::lambda + param::log_alpha + 2);
327	  if (p <= q_with_slack_p) return coinbase::error(E_CRYPTO);
328	
329	  const mod_t& N = paillier.get_N();
330	  if (N <= 0) return coinbase::error(E_CRYPTO);
331	
332	  bn_t q_with_slack_N = q << (SEC_P_STAT + param::lambda + 2 * param::log_alpha + 1);
333	  if (N <= q_with_slack_N) return coinbase::error(E_CRYPTO);
334	
335	  if (rv = params.check_safe_prime_subgroup(Com)) return rv;
336	  if (rv = params.check_safe_prime_subgroup(Com_tilde)) return rv;
337	
338	  if (paillier_no_small_factors == zk_flag::unverified) {
339	    if (rv = check_integer_with_small_primes(N, param::alpha)) return rv;
340	    paillier_no_small_factors = zk_flag::verified;
341	  }
342	
343	  if (e < 0) return coinbase::error(E_CRYPTO, "paillier_pedersen_equal_t::verify: e < 0");
344	  if (nu < 0) return coinbase::error(E_CRYPTO, "paillier_pedersen_equal_t::verify: nu < 0");
345	
346	  // The following verification of `paillier.verify_cipher(c))` is removed and instead done with `D_prod`
347	  // later on to increase efficiency and save a GCD operation.
348	
349	  bn_t q_with_slack = q << (param::log_alpha + SEC_P_STAT);
350	  const mod_t& NN = paillier.get_NN();
351	
352	  bn_t e_temp = e;
353	  bn_t radix = 1 << param::log_alpha;
354	
355	  if (rv = coinbase::crypto::check_open_range(0, c, NN))
356	    return coinbase::error(rv, "paillier_pedersen_equal_t::verify: invalid ciphertext c");
357	
358	  bn_t D_prod = c;
359	  bn_t d = 0;
360	  for (int i = 0; i < param::t; i++) {
361	    MODULO(N) D_prod *= D[i];
362	
363	    if (rv = coinbase::crypto::check_open_range(0, D[i], N)) return rv;
364	
365	    if (rv = coinbase::crypto::check_open_range(0, di[i], q_with_slack)) return rv;
366	    d += di[i] << (i * param::log_alpha);
367	  }
368	  if (D_prod == 0) return coinbase::error(E_CRYPTO);
369	  if (!mod_t::coprime(D_prod, N)) return coinbase::error(E_CRYPTO);
370	
371	  bn_t c_inv = NN.inv(c);
372	  crypto::paillier_t::elem_t c_tilde[param::t];
373	  e_temp = e;
374	  for (int i = 0; i < param::t; i++) {
375	    bn_t ei = mod_t::mod(e_temp, radix);
376	    e_temp >>= param::log_alpha;
377	    crypto::paillier_t::elem_t c_tag(paillier, c_inv.pow_mod(ei, NN));
378	    c_tilde[i] = c_tag + paillier.enc(di[i], D[i]);
379	  }
380	
381	  buf_t e_buf =
382	      crypto::ro::hash_string(N, c, p, q, g, h, Com, c_tilde, Com_tilde, session_id, aux).bitlen(param::lambda);
383	  bn_t e_tag = bn_t::from_bin_bitlen(e_buf, param::lambda);
384	  if (e != e_tag) return coinbase::error(E_CRYPTO, "e' != e");
385	
386	  bn_t temp1, temp2;
387	  MODULO(p) {
388	    temp1 = Com.pow(e) * Com_tilde;
389	    temp2 = g.pow(d) * h.pow(nu);
390	  }
391	
392	  if (temp1 != temp2) return coinbase::error(E_CRYPTO);
393	  return SUCCESS;
394	}
395	
396	void paillier_pedersen_equal_interactive_t::prover_msg1(const crypto::paillier_t& paillier, const mod_t& q) {
397	  // In our use cases, all our provers have private keys. If not, we would need to verify that gcd(R_tilde[i],N) = 1
398	  cb_assert(paillier.has_private_key());
399	
400	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
401	  const mod_t& p = params.p;
402	  const mod_t& p_tag = params.p_tag;
403	  const bn_t& g = params.g;
404	  const bn_t& h = params.h;
405	
406	  const mod_t& N = paillier.get_N();
407	  bn_t q_with_slack_p = q << (SEC_P_STAT + param::lambda + param::log_alpha + 2);
408	  cb_assert(p > q_with_slack_p);
409	
410	  bn_t q_with_slack_N = q << (SEC_P_STAT + param::lambda + 2 * param::log_alpha + 1);
411	  cb_assert(N > q_with_slack_N);
412	
413	  bn_t q_with_slack = q << (param::log_alpha + SEC_P_STAT);
414	
415	  mu = bn_t::rand(p_tag);
416	  r = 0;
417	  for (int i = 0; i < param::t; i++) {
418	    ri[i] = bn_t::rand(q_with_slack);
419	    R_tilde[i] = bn_t::rand(N);
420	    c_tilde[i] = paillier.encrypt(ri[i], R_tilde[i]);
421	    r += ri[i] << (i * param::log_alpha);
422	  }
423	
424	  MODULO(p) Com_tilde = g.pow(r) * h.pow(mu);
425	
426	  com.id(prover_pid).gen(c_tilde, Com_tilde);
427	}
