429	void paillier_pedersen_equal_interactive_t::verifier_challenge() { e = bn_t::rand_bitlen(param::t * param::log_alpha); }
430	
431	void paillier_pedersen_equal_interactive_t::prover_msg2(const crypto::paillier_t& paillier, const bn_t& x,
432	                                                        const bn_t& R, const bn_t& rho) {
433	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
434	  const mod_t& p_tag = params.p_tag;
435	  const mod_t& N = paillier.get_N();
436	
437	  bn_t e_temp = e;
438	
439	  for (int i = 0; i < param::t; i++) {
440	    bn_t ei;
441	    {
442	      crypto::vartime_scope_t vartime_scope;
443	      ei = mod_t::mod(e_temp, param::alpha);
444	      e_temp >>= (param::log_alpha);
445	    }
446	
447	    di[i] = x * ei + ri[i];
448	    MODULO(N) Di[i] = R.pow(ei) * R_tilde[i];
449	  }
450	  MODULO(p_tag) nu = e * rho + mu;
451	}
452	
453	error_t paillier_pedersen_equal_interactive_t::verify(const crypto::paillier_t& paillier, const bn_t& c, const mod_t& q,
454	                                                      const bn_t& Com) {
455	  error_t rv = UNINITIALIZED_ERROR;
456	  crypto::vartime_scope_t vartime_scope;
457	
458	  const mod_t& N = paillier.get_N();
459	  const mod_t& NN = paillier.get_NN();
460	
461	  if (paillier_valid_key == zk_flag::unverified) return coinbase::error(E_CRYPTO);
462	  if (paillier_no_small_factors == zk_flag::unverified) {
463	    if (rv = check_integer_with_small_primes(N, param::alpha)) return rv;
464	    paillier_no_small_factors = zk_flag::verified;
465	  }
466	
467	  if (e < 0) return coinbase::error(E_CRYPTO, "paillier_pedersen_equal_interactive_t::verify: e < 0");
468	  if (nu < 0) return coinbase::error(E_CRYPTO, "paillier_pedersen_equal_interactive_t::verify: nu < 0");
469	
470	  const pedersen_commitment_params_t& params = pedersen_commitment_params_t::get();
471	  const mod_t& p = params.p;
472	  const bn_t& g = params.g;
473	  const bn_t& h = params.h;
474	
475	  if (N <= 0) return coinbase::error(E_CRYPTO);
476	
477	  bn_t q_with_slack_p = q << (SEC_P_STAT + param::lambda + param::log_alpha + 2);
478	  if (p <= q_with_slack_p) return coinbase::error(E_CRYPTO);
479	
480	  bn_t q_with_slack_N = q << (SEC_P_STAT + param::lambda + 2 * param::log_alpha + 1);
481	  if (N <= q_with_slack_N) return coinbase::error(E_CRYPTO);
482	
483	  // Similar to the non-interactive version, we do not verify the ciphertext here and include it in `CD`
484	
485	  if (rv = com.id(prover_pid).open(c_tilde, Com_tilde)) return rv;
486	
487	  if (rv = params.check_safe_prime_subgroup(Com)) return rv;
488	  if (rv = params.check_safe_prime_subgroup(Com_tilde)) return rv;
489	
490	  bn_t d = 0;
491	  bn_t CD = c;
492	  bn_t q_with_slack = q << (param::log_alpha + SEC_P_STAT);
493	
494	  for (int i = 0; i < param::t; i++) {
495	    if (rv = coinbase::crypto::check_right_open_range(0, di[i], q_with_slack)) return rv;
496	    if (rv = coinbase::crypto::check_open_range(0, Di[i], N)) return rv;
497	    MODULO(N) CD *= Di[i] * c_tilde[i];
498	  }
499	
500	  if (CD == 0) return coinbase::error(E_CRYPTO);
501	  if (!mod_t::coprime(CD, N)) return coinbase::error(E_CRYPTO);
502	
503	  bn_t e_temp = e;
504	  bn_t radix = 1 << param::log_alpha;
505	  for (int i = 0; i < param::t; i++) {
506	    bn_t ei = mod_t::mod(e_temp, radix);
507	    e_temp >>= param::log_alpha;
508	
509	    bn_t C;
510	    MODULO(NN) { C = (c_tilde[i] * c.pow(ei)); }
511	    if (C != paillier.encrypt(di[i], Di[i])) return coinbase::error(E_CRYPTO);
512	
513	    d += di[i] << (i * param::log_alpha);
514	  }
515	
516	  bn_t C1, C2;
517	  MODULO(p) {
518	    C1 = Com.pow(e) * Com_tilde;
519	    C2 = g.pow(d) * h.pow(nu);
520	  }
521	  if (C1 != C2) return coinbase::error(E_CRYPTO);
522	
523	  return SUCCESS;
524	}
