6	void unknown_order_dl_t::prove(const bn_t& a, const bn_t& b, const mod_t& N, const int l, const bn_t& w, mem_t sid,
7	                               const uint64_t aux) {
8	  cb_assert(w.get_bits_count() <= l);
9	  int r_size = l + SEC_P_STAT + 1;
10	
11	  bn_t gcd_test;
12	  MODULO(N) gcd_test = a * b;
13	  cb_assert(mod_t::coprime(gcd_test, N) && "unknown_order_dl_t::prove: gcd(a*b, N) != 1");
14	
15	  bn_t R[SEC_P_COM];
16	  for (int i = 0; i < SEC_P_COM; i++) {
17	    z[i] = bn_t::rand_bitlen(r_size);
18	    MODULO(N) R[i] = a.pow(z[i]);
19	  }
20	
21	  e = crypto::ro::hash_string(a, b, N, l, R, sid, aux).bitlen(SEC_P_COM);
22	
23	  for (int i = 0; i < SEC_P_COM; i++) {
24	    if (coinbase::bits_t::get(e.data(), i)) z[i] = z[i] + w;
25	  }
26	}
27	
28	error_t unknown_order_dl_t::verify(const bn_t& a, const bn_t& b, const mod_t& N, const int l, mem_t sid,
29	                                   uint64_t aux) const {
30	  crypto::vartime_scope_t vartime_scope;
31	  error_t rv = UNINITIALIZED_ERROR;
32	
33	  if (l <= 0) return coinbase::error(E_CRYPTO, "unknown_order_dl_t::verify: l <= 0");
34	  if (e.size() != coinbase::bits_to_bytes(SEC_P_COM))
35	    return coinbase::error(E_CRYPTO, "unknown_order_dl_t::verify: invalid e size");
36	
37	  // Ensure `b` is invertible mod N before attempting BN_mod_inverse (which asserts on failure).
38	  if (rv = coinbase::crypto::check_open_range(0, b, N))
39	    return coinbase::error(rv, "unknown_order_dl_t::verify: invalid b");
40	  if (!mod_t::coprime(b, N)) return coinbase::error(E_CRYPTO, "unknown_order_dl_t::verify: gcd(b, N) != 1");
41	
42	  const int max_z_bits = l + SEC_P_STAT + 2;
43	  for (int i = 0; i < SEC_P_COM; i++) {
44	    if (z[i] < 0) return coinbase::error(E_CRYPTO, "unknown_order_dl_t::verify: z[i] < 0");
45	    if (z[i].get_bits_count() > max_z_bits)
46	      return coinbase::error(E_CRYPTO, "unknown_order_dl_t::verify: z[i] too large");
47	  }
48	
49	  bn_t gcd_test;
50	  MODULO(N) gcd_test = a * b;
51	  if (!mod_t::coprime(gcd_test, N)) return coinbase::error(E_CRYPTO, "unknown_order_dl_t::verify: gcd(a*b, N) != 1");
52	
53	  bn_t b_inv = N.inv(b);
54	
55	  bn_t R_tag;
56	  MODULO(N) R_tag = a * b;
57	
58	  bn_t R[SEC_P_COM];
59	  for (int i = 0; i < SEC_P_COM; i++) {
60	    MODULO(N) R[i] = a.pow(z[i]);
61	    if (coinbase::bits_t::get(e.data(), i)) MODULO(N) R[i] = R[i] * b_inv;
62	
63	    MODULO(N) R_tag *= R[i];
64	  }
65	
66	  buf_t e_tag = crypto::ro::hash_string(a, b, N, l, R, sid, aux).bitlen(SEC_P_COM);
67	  if (e != e_tag) {
68	    return coinbase::error(E_CRYPTO);
69	  }
70	
71	  if (!mod_t::coprime(R_tag, N)) return coinbase::error(E_CRYPTO);
72	  return SUCCESS;
73	}
