135	void elgamal_com_mult_t::prove(const ecc_point_t& Q, const elg_com_t& A, const elg_com_t& B, const elg_com_t& C,
136	                               const bn_t& r_B, const bn_t& r_C, const bn_t& b, mem_t session_id, uint64_t aux) {
137	  ecurve_t curve = Q.get_curve();
138	  const mod_t& q = curve.order();
139	
140	  bn_t r1 = bn_t::rand(q);
141	  bn_t r2 = bn_t::rand(q);
142	  bn_t r3 = bn_t::rand(q);
143	  auto R = crypto::ec_elgamal_commitment_t::commit(Q, r1).rand(r2);
144	  auto A_tag = (r1 * A).rerand(Q, r3);
145	  e = crypto::ro::hash_number(Q, R, A_tag, A, B, C, session_id, aux).mod(q);
146	
147	  MODULO(q) {
148	    z1 = r1 + e * b;
149	    z2 = r2 + e * r_B;
150	    z3 = r3 + e * r_C;
151	  }
152	}
