154	error_t elgamal_com_mult_t::verify(const ecc_point_t& Q, const elg_com_t& A, const elg_com_t& B, const elg_com_t& C,
155	                                   mem_t session_id, uint64_t aux) const {
156	  error_t rv = UNINITIALIZED_ERROR;
157	  crypto::vartime_scope_t vartime_scope;
158	
159	  ecurve_t curve = Q.get_curve();
160	  if (rv = curve.check(Q)) return coinbase::error(rv, "elgamal_com_mult_t::verify: check Q failed");
161	  if (rv = A.check_curve(curve)) return coinbase::error(rv, "elgamal_com_mult_t::verify: check A failed");
162	  if (rv = B.check_curve(curve)) return coinbase::error(rv, "elgamal_com_mult_t::verify: check B failed");
163	  if (rv = C.check_curve(curve)) return coinbase::error(rv, "elgamal_com_mult_t::verify: check C failed");
164	
165	  const mod_t& q = curve.order();
166	
167	  if (rv = crypto::check_right_open_range(0, e, q)) return rv;
168	  if (rv = crypto::check_right_open_range(0, z1, q)) return rv;
169	  if (rv = crypto::check_right_open_range(0, z2, q)) return rv;
170	  if (rv = crypto::check_right_open_range(0, z3, q)) return rv;
171	
172	  auto R = crypto::ec_elgamal_commitment_t::commit(Q, z1).rand(z2) - e * B;
173	  auto A_tag = (z1 * A).rerand(Q, z3) - e * C;
174	  bn_t e_tag = crypto::ro::hash_number(Q, R, A_tag, A, B, C, session_id, aux).mod(q);
175	  if (e != e_tag) return coinbase::error(E_CRYPTO, "e != e'");
176	  return SUCCESS;
177	}
