239	error_t uc_elgamal_com_mult_private_scalar_t::verify(const ecc_point_t& Q, const elg_com_t& A, const elg_com_t& B,
240	                                                     mem_t session_id, uint64_t aux) {
241	  error_t rv = UNINITIALIZED_ERROR;
242	  crypto::vartime_scope_t vartime_scope;
243	  if (rv = params.check()) return rv;
244	  int rho = params.rho;
245	  if (int(A1_tag.size()) != rho) return coinbase::error(E_CRYPTO);
246	  if (int(A2_tag.size()) != rho) return coinbase::error(E_CRYPTO);
247	  if (int(e.size()) != rho) return coinbase::error(E_CRYPTO);
248	  if (int(z1.size()) != rho) return coinbase::error(E_CRYPTO);
249	  if (int(z2.size()) != rho) return coinbase::error(E_CRYPTO);
250	
251	  ecurve_t curve = Q.get_curve();
252	  if (rv = curve.check(Q)) return coinbase::error(rv, "uc_elgamal_com_mult_private_scalar_t::verify: check Q failed");
253	  if (rv = A.check_curve(curve))
254	    return coinbase::error(rv, "uc_elgamal_com_mult_private_scalar_t::verify: check A failed");
255	  if (rv = B.check_curve(curve))
256	    return coinbase::error(rv, "uc_elgamal_com_mult_private_scalar_t::verify: check B failed");
257	
258	  const mod_t& q = curve.order();
259	  const auto& G = curve.generator();
260	  uint32_t b_mask = params.b_mask();
261	
262	  for (int i = 0; i < rho; i++) {
263	    if (rv = curve.check(A1_tag[i]))
264	      return coinbase::error(rv, "uc_elgamal_com_mult_private_scalar_t::verify: check A1_tag failed");
265	    if (rv = curve.check(A2_tag[i]))
266	      return coinbase::error(rv, "uc_elgamal_com_mult_private_scalar_t::verify: check A2_tag failed");
267	    if (rv = crypto::check_right_open_range(0, z1[i], q)) return rv;
268	    if (rv = crypto::check_right_open_range(0, z2[i], q)) return rv;
269	  }
270	
271	  buf_t common_hash = crypto::ro::hash_string(Q, A, B, A1_tag, A2_tag, session_id, aux).bitlen(2 * SEC_P_COM);
272	
273	  bn_t z1_sum = 0;
274	  bn_t z2_sum = 0;
275	  bn_t e_sum = 0;
276	  ecc_point_t A1_sum = curve.infinity();
277	  ecc_point_t A2_sum = curve.infinity();
278	
279	  for (int i = 0; i < rho; i++) {
280	    bn_t sigma = bn_t::rand_bitlen(SEC_P_STAT);
281	    MODULO(q) {
282	      z1_sum += sigma * z1[i];
283	      z2_sum += sigma * z2[i];
284	      e_sum += sigma * bn_t(e[i]);
285	    }
286	    A1_sum += sigma * A1_tag[i];
287	    A2_sum += sigma * A2_tag[i];
288	
289	    uint32_t h = hash32bit_for_zk_fischlin(common_hash, i, e[i], z1[i], z2[i]) & b_mask;
290	    if (h != 0) return coinbase::error(E_CRYPTO);
291	  }
292	
293	  const ecc_point_t& A1 = A.L;
294	  const ecc_point_t& A2 = A.R;
295	  const ecc_point_t& B1 = B.L;
296	  const ecc_point_t& B2 = B.R;
297	
298	  if (A1_sum != z1_sum * A1 + z2_sum * G - e_sum * B1) return coinbase::error(E_CRYPTO);
299	  if (A2_sum != z1_sum * A2 + z2_sum * Q - e_sum * B2) return coinbase::error(E_CRYPTO);
300	  return SUCCESS;
301	}
