8	// Variadic template function to serialize all bn_t objects and update the SHA256 context
9	inline void sha256_update_zs(EVP_MD_CTX* ctx) {}
10	template <typename... REST>
11	void sha256_update_zs(EVP_MD_CTX* ctx, const bn_t& first, REST&... rest) {
12	  alignas(64) byte_t temp[256];
13	
14	  cb_assert(first.get_bin_size() <= 256);  // prevent stack overflow
15	
16	  int len = first.to_bin(temp);
17	  // Length-prefix each element to avoid ambiguous concatenation across multiple `bn_t`s:
18	  // without this, tuples like (0x01, 0x02) and (0x0102, 0x00) hash identically.
19	  byte_t len_be[4];
20	  coinbase::be_set_4(len_be, uint32_t(len));
21	  EVP_DigestUpdate(ctx, len_be, sizeof(len_be));
22	  EVP_DigestUpdate(ctx, temp, len);
23	
24	  sha256_update_zs(ctx, rest...);
25	}
26	
27	// Hard-coded to hash32, since `b` is at most 32
28	template <typename... BN_TS>
29	uint32_t hash32bit_for_zk_fischlin(mem_t common_hash, int i, int j, BN_TS&... zs) {
30	  EVP_MD_CTX* ctx = EVP_MD_CTX_new();
31	  EVP_DigestInit(ctx, EVP_sha256());
32	  EVP_DigestUpdate(ctx, common_hash.data, common_hash.size);
33	
34	  byte_t temp[32];
35	  coinbase::be_set_4(temp + 0, i);
36	  coinbase::be_set_4(temp + 4, j);
37	  EVP_DigestUpdate(ctx, temp, 8);
38	
39	  sha256_update_zs(ctx, zs...);
40	
41	  unsigned int hash_len = 0;
42	  EVP_DigestFinal(ctx, temp, &hash_len);
43	  EVP_MD_CTX_free(ctx);
44	  return coinbase::be_get_4(temp);
45	}
