47	struct fischlin_params_t {
48	  int rho, b, t;
49	
50	  int e_max() const {
51	    cb_assert(t < 31);
52	    return 1U << t;
53	  }
54	  uint32_t b_mask() const {
55	    cb_assert(b < 31);
56	    return (1U << b) - 1;
57	  }
58	  error_t check() const {
59	    if (rho <= 0) return coinbase::error(E_CRYPTO, "rho <= 0");
60	    if (b <= 0) return coinbase::error(E_CRYPTO, "b <= 0");
61	    if (b >= 31) return coinbase::error(E_CRYPTO, "b >= 31");
62	    if (int64_t(b) * int64_t(rho) < SEC_P_COM) return coinbase::error(E_CRYPTO, "b * rho < SEC_P_COM");
63	    return SUCCESS;
64	  }
65	
66	  error_t check_with_effective_b(int effective_b) const {
67	    if (rho <= 0) return coinbase::error(E_CRYPTO, "rho <= 0");
68	    if (b <= 0) return coinbase::error(E_CRYPTO, "b <= 0");
69	    if (b >= 31) return coinbase::error(E_CRYPTO, "b >= 31");
70	
71	    if (effective_b <= 0) return coinbase::error(E_CRYPTO, "effective_b <= 0");
72	    if (int64_t(rho) * int64_t(effective_b) < SEC_P_COM)
73	      return coinbase::error(E_CRYPTO, "rho * effective_b < SEC_P_COM");
74	    return SUCCESS;
75	  }
76	  void convert(coinbase::converter_t& c) { c.convert(rho, b); }  // t is not sent
77	};
